1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	};
11	
12	interface QuoteStep {
13	  op: "quote";
14	  items: { type: string }[];
15	}
16	
17	interface Scenario {
18	  customer: { yearsWithMHPCO: number };
19	  steps: QuoteStep[];
20	}
21	
22	const priceQuote = (items: { type: string }[]): { premium: number } => {
23	  const policyBase = items.reduce(
24	    (sum, item) => sum + (BASE_PREMIUMS[item.type] ?? 0),
25	    0,
26	  );
27	  const firstInsurance = policyBase * FIRST_INSURANCE_RATE;
28	  const premium = Math.ceil(policyBase + firstInsurance + PROCESSING_FEE);
29	  return { premium };
30	};
31	
32	export const runScenario = (scenario: Scenario): { results: unknown[] } => {
33	  const results = scenario.steps.map((step) => priceQuote(step.items));
34	  return { results };
35	};
